/* =====================================================
   NWL — edit your products here.
   Add / remove items from this list any time.
   colour must be "Black" or "White".
   img / imgBack point to entries in IMAGES below.
===================================================== */
const CLOTHING_SIZES = ["XS","S","M","L","XL"];
const PRODUCTS = [
  {id:1, name:"Lips Tee",           cat:"Tees",        colour:"White", price:25, sizes:CLOTHING_SIZES, img:"lips_1",    imgBack:"lips_2"},
  {id:2, name:"Hazard Tee",         cat:"Tees",        colour:"White", price:20, sizes:CLOTHING_SIZES, img:"hazard_1",  imgBack:"lips_2"},
  {id:3, name:"The Mercs White",    cat:"Tees",        colour:"White", price:20, sizes:CLOTHING_SIZES, img:"mercs_w_1", imgBack:"lips_2"},
  {id:4, name:"The Mercs Black",    cat:"Tees",        colour:"Black", price:20, sizes:CLOTHING_SIZES, img:"mercs_b_1", imgBack:"mercs_b_2"},
  {id:5, name:"Brazil Jersey",      cat:"Jerseys",     colour:"Black", price:25, sizes:CLOTHING_SIZES, img:"brazil_1",  imgBack:"brazil_2"},
  {id:6, name:"England Jersey",     cat:"Jerseys",     colour:"Black", price:25, sizes:CLOTHING_SIZES, img:"england_1", imgBack:"england_2"},
  {id:7, name:"Morocco Sweatshirt", cat:"Sweatshirts", colour:"Black", price:30, sizes:CLOTHING_SIZES, img:"morocco_1", imgBack:"morocco_2"},
  {id:8, name:"Last Dance Shorts",  cat:"Shorts",      colour:"Black", price:15, sizes:CLOTHING_SIZES, img:"shorts_1",  imgBack:"shorts_2"},
];
const IMAGES = {
  "lips_1": "data:image/jpeg;base64,",
  "lips_2": "data:image/jpeg;base64,",
  "brazil_1": "data:image/jpeg;base64,",
  "brazil_2": "data:image/jpeg;base64,",
  "england_1": "data:image/jpeg;base64,",
  "england_2": "data:image/jpeg;base64,",
  "hazard_1": "data:image/jpeg;base64,",
  "morocco_1": "data:image/jpeg;base64,",
  "shorts_1": "data:image/jpeg;base64,",
  "shorts_2": "data:image/jpeg;base64,",
  "mercs_b_1": "data:image/jpeg;base64,",
  "mercs_b_2": "data:image/jpeg;base64,",
  "mercs_w_1": "data:image/jpeg;base64,",
  "morocco_2": "data:image/jpeg;base64,"
};
const COLLECTIONS = ["All","Tees","Hoodies","Zip-Ups","Sweatshirts","Joggers","Jorts","Shorts","Jerseys","Accessories"];
const PRICE_BANDS = [
  {label:"Under £20", test:p=>p.price<20},
  {label:"£20–£25",  test:p=>p.price>=20&&p.price<=25},
  {label:"Over £25", test:p=>p.price>25},
];

/* ---------- state (kept in memory) ---------- */
const state = {collection:"All", size:null, colour:null, priceBand:null};
const wishlist = new Set();
const recentlyViewed = [];
let currentProduct = null, selectedSize = null;

const $ = id => document.getElementById(id);
const gbp = n => "£" + n;

/* Orders happen by email — this opens Gmail with the message pre-filled */
const SHOP_EMAIL = "nwl.garms@gmail.com";
const IS_MOBILE = /Android|iPhone|iPad|iPod/i.test(navigator.userAgent);
function openGmail(subject, body){
  const su = encodeURIComponent(subject), bo = encodeURIComponent(body);
  if(IS_MOBILE){
    // phones: mailto opens the Gmail app (or default mail app) with everything pre-filled
    window.location.href = "mailto:" + SHOP_EMAIL + "?subject=" + su + "&body=" + bo;
  } else {
    // desktop: open Gmail web compose in a new tab
    window.open("https://mail.google.com/mail/?view=cm&fs=1&to=" + SHOP_EMAIL + "&su=" + su + "&body=" + bo, "_blank", "noopener");
  }
}
/* static email links (contact card + footer) route through the same logic */
document.querySelectorAll(".gmail-link").forEach(a=>{
  a.addEventListener("click", e=>{
    e.preventDefault();
    openGmail("NWL Order", "Hi NWL,\n\nI'd like to order:\n\n");
  });
});

/* ---------- toast ---------- */
let toastTimer;
function toast(msg){
  const t = $("toast");
  t.textContent = msg;
  t.classList.add("show");
  clearTimeout(toastTimer);
  toastTimer = setTimeout(()=>t.classList.remove("show"), 2200);
}

/* ---------- marquee: duplicate content for a seamless loop ---------- */
$("marqueeTrack").innerHTML += $("marqueeTrack").innerHTML;

/* ---------- tabs ---------- */
function renderTabs(){
  $("tabs").innerHTML = COLLECTIONS.map(c =>
    `<button class="tab ${state.collection===c?"active":""}" role="tab" aria-selected="${state.collection===c}" data-col="${c}">${c}</button>`
  ).join("");
}
$("tabs").addEventListener("click", e=>{
  const b = e.target.closest("[data-col]");
  if(!b) return;
  state.collection = b.dataset.col;
  renderTabs(); renderGrid();
});

/* ---------- filters ---------- */
function renderFilters(){
  $("sizeFilters").innerHTML = CLOTHING_SIZES.map(s =>
    `<button class="chip ${state.size===s?"active":""}" data-size="${s}">${s}</button>`).join("");
  $("colourFilters").innerHTML = ["Black","White"].map(c =>
    `<button class="chip ${state.colour===c?"active":""}" data-colour="${c}"><span class="swatch" style="background:${c==="Black"?"#000":"#fff"};margin-right:6px;vertical-align:-1px"></span>${c}</button>`).join("");
  $("priceFilters").innerHTML = PRICE_BANDS.map((b,i) =>
    `<button class="chip ${state.priceBand===i?"active":""}" data-price="${i}">${b.label}</button>`).join("");
}
document.querySelector(".filters").addEventListener("click", e=>{
  const chip = e.target.closest(".chip");
  if(chip){
    if(chip.dataset.size)   state.size   = state.size===chip.dataset.size ? null : chip.dataset.size;
    if(chip.dataset.colour) state.colour = state.colour===chip.dataset.colour ? null : chip.dataset.colour;
    if(chip.dataset.price!==undefined){ const i=+chip.dataset.price; state.priceBand = state.priceBand===i ? null : i; }
    renderFilters(); renderGrid();
  }
});
$("clearFilters").addEventListener("click", ()=>{
  state.size=null; state.colour=null; state.priceBand=null;
  renderFilters(); renderGrid();
});

/* ---------- filtering logic ---------- */
function filtered(){
  return PRODUCTS.filter(p=>{
    if(state.collection!=="All" && p.cat!==state.collection) return false;
    if(state.size && !p.sizes.includes(state.size)) return false;
    if(state.colour && p.colour!==state.colour) return false;
    if(state.priceBand!==null && !PRICE_BANDS[state.priceBand].test(p)) return false;
    return true;
  });
}

/* ---------- product grid ---------- */
function cardHTML(p){
  return `<article class="card">
    <div class="card-img has-photo" data-open="${p.id}" role="button" tabindex="0" aria-label="View ${p.name}">
      <img src="${IMAGES[p.img]}" alt="${p.name}" loading="lazy">
      <button class="wish-btn ${wishlist.has(p.id)?"saved":""}" data-wish="${p.id}" aria-label="Save ${p.name} to wishlist">${wishlist.has(p.id)?"♥":"♡"}</button>
    </div>
    <div class="card-body">
      <div class="card-cat">${p.cat}</div>
      <div class="card-name">${p.name}</div>
      <div class="card-foot">
        <span class="card-price">${gbp(p.price)}</span>
        <span class="card-colour"><span class="swatch" style="background:${p.colour==="Black"?"#000":"#fff"}"></span>${p.colour}</span>
      </div>
    </div>
  </article>`;
}
function renderGrid(){
  const items = filtered();
  $("resultCount").textContent = items.length + (items.length===1 ? " item" : " items");
  const cats = COLLECTIONS.slice(1); // every category except "All"
  let html = "";
  cats.forEach(cat=>{
    const catItems = items.filter(p=>p.cat===cat);
    if(!catItems.length) return;
    html += `<section class="cat-section">
      <div class="cat-head"><h3 class="cat-title">${cat}</h3><span class="cat-count">${catItems.length} ${catItems.length===1?"piece":"pieces"}</span></div>
      <div class="grid">${catItems.map(cardHTML).join("")}</div>
    </section>`;
  });
  $("shopSections").innerHTML = html ||
    `<div class="empty-state"><strong>Nothing here (yet)</strong>No pieces match those filters. Try clearing a filter — or wait for next month's drop.</div>`;
}

/* ---------- grid clicks: open product / toggle wishlist ---------- */
document.body.addEventListener("click", e=>{
  const wishBtn = e.target.closest("[data-wish]");
  if(wishBtn){ e.stopPropagation(); toggleWish(+wishBtn.dataset.wish); return; }
  const opener = e.target.closest("[data-open]");
  if(opener) openQuickView(+opener.dataset.open);
});
document.body.addEventListener("keydown", e=>{
  if(e.key==="Enter"){
    const opener = e.target.closest("[data-open]");
    if(opener) openQuickView(+opener.dataset.open);
  }
  if(e.key==="Escape") document.querySelectorAll(".overlay.open").forEach(closeOverlay);
});

/* ---------- wishlist ---------- */
function toggleWish(id){
  const p = PRODUCTS.find(x=>x.id===id);
  if(wishlist.has(id)){ wishlist.delete(id); toast("Removed from wishlist"); }
  else { wishlist.add(id); toast(p.name + " saved ♥"); }
  $("wishCount").textContent = wishlist.size;
  renderGrid(); renderWishModal();
  if(currentProduct && currentProduct.id===id) syncQvWishBtn();
}
function renderWishModal(){
  const box = $("wishList");
  if(!wishlist.size){ box.innerHTML = `<p class="modal-empty">Nothing saved yet. Tap the ♡ on any piece you're feeling.</p>`; return; }
  box.innerHTML = [...wishlist].map(id=>{
    const p = PRODUCTS.find(x=>x.id===id);
    return `<div class="list-item">
      <div class="list-thumb has-photo"><img src="${IMAGES[p.img]}" alt=""></div>
      <div class="list-info"><div class="list-name">${p.name}</div><div class="list-meta">${p.cat} · ${p.colour} · ${gbp(p.price)}</div></div>
      <button class="list-remove" data-wish="${id}">Remove</button>
    </div>`;
  }).join("")
  + `<button class="btn-primary" id="wishEmail" style="width:100%;margin-top:8px">Email us this wishlist</button>
     <p class="modal-empty" style="margin-top:8px">Opens Gmail with your saved pieces ready to send — just add your sizes.</p>`;
  $("wishEmail").addEventListener("click", ()=>{
    const lines = [...wishlist].map(id=>{
      const p = PRODUCTS.find(x=>x.id===id);
      return `- ${p.name} (${p.colour}, ${gbp(p.price)}) — size: `;
    }).join("\n");
    openGmail("NWL Order", "Hi NWL,\n\nI'd like to order:\n\n" + lines + "\n\nMy address:\n\nThanks!");
  });
}

/* ---------- recently viewed & recommendations ---------- */
function miniCardHTML(p){
  return `<div class="mini-card" data-open="${p.id}" role="button" tabindex="0" aria-label="View ${p.name}">
    <div class="mini-img has-photo"><img src="${IMAGES[p.img]}" alt="${p.name}" loading="lazy"></div>
    <div class="mini-body"><div class="mini-name">${p.name}</div><div class="mini-price">${p.cat} · ${gbp(p.price)}</div></div>
  </div>`;
}
function renderRecent(){
  if(!recentlyViewed.length) return;
  $("recentSection").style.display = "block";
  $("recentRow").innerHTML = recentlyViewed.map(id=>miniCardHTML(PRODUCTS.find(p=>p.id===id))).join("");
}
function recsFor(p, n){
  const same = PRODUCTS.filter(x=>x.id!==p.id && x.cat===p.cat);
  const rest = PRODUCTS.filter(x=>x.id!==p.id && x.cat!==p.cat).sort(()=>Math.random()-.5);
  return same.concat(rest).slice(0,n);
}
function renderHomeRecs(){
  const seed = recentlyViewed.length ? PRODUCTS.find(p=>p.id===recentlyViewed[0]) : PRODUCTS[Math.floor(Math.random()*PRODUCTS.length)];
  $("recsRow").innerHTML = recsFor(seed,6).map(miniCardHTML).join("");
}

/* ---------- quick view ---------- */
function openQuickView(id){
  const p = PRODUCTS.find(x=>x.id===id);
  currentProduct = p; selectedSize = p.sizes.length===1 ? p.sizes[0] : null;

  $("qvImg").className = "qv-img has-photo";
  $("qvImg").innerHTML = `<img src="${IMAGES[p.img]}" alt="${p.name}">`
    + (p.imgBack ? `<button class="flip-btn" id="qvFlip" aria-label="Flip to other side">Flip ⇄</button>` : "");
  if(p.imgBack){
    let showingBack = false;
    $("qvFlip").addEventListener("click", ()=>{
      showingBack = !showingBack;
      $("qvImg").querySelector("img").src = IMAGES[showingBack ? p.imgBack : p.img];
    });
  }
  $("qvCat").textContent = p.cat;
  $("qvName").textContent = p.name;
  $("qvPrice").textContent = gbp(p.price);
  $("qvColour").innerHTML = `<span class="swatch" style="background:${p.colour==="Black"?"#000":"#fff"}"></span>${p.colour}`;
  $("qvSizes").innerHTML = p.sizes.map(s=>
    `<button class="size-opt ${selectedSize===s?"active":""}" data-qv-size="${s}">${s}</button>`).join("");
  syncQvWishBtn();
  $("qvRecsRow").innerHTML = recsFor(p,4).map(miniCardHTML).join("");
  openOverlay("qvOverlay");

  // track recently viewed (most recent first, no duplicates, max 8)
  const i = recentlyViewed.indexOf(id);
  if(i>-1) recentlyViewed.splice(i,1);
  recentlyViewed.unshift(id);
  if(recentlyViewed.length>8) recentlyViewed.pop();
  renderRecent(); renderHomeRecs();
}
function syncQvWishBtn(){
  const saved = currentProduct && wishlist.has(currentProduct.id);
  $("qvAddWish").textContent = saved ? "♥ Saved" : "♡ Save";
}
$("qvSizes").addEventListener("click", e=>{
  const b = e.target.closest("[data-qv-size]");
  if(!b) return;
  selectedSize = b.dataset.qvSize;
  $("qvSizes").querySelectorAll(".size-opt").forEach(x=>x.classList.toggle("active", x.dataset.qvSize===selectedSize));
});
$("qvOrder").addEventListener("click", ()=>{
  if(!selectedSize){ toast("Pick a size first"); return; }
  const p = currentProduct;
  openGmail(
    "NWL Order — " + p.name,
    `Hi NWL,\n\nI'd like to order:\n\n${p.name}\nColour: ${p.colour}\nSize: ${selectedSize}\nPrice: ${gbp(p.price)}\n\nMy address:\n\nThanks!`
  );
  toast("Opening Gmail…");
});
$("qvAddWish").addEventListener("click", ()=> toggleWish(currentProduct.id));

/* ---------- modal open/close wiring ---------- */
function openOverlay(id){
  $(id).classList.add("open");
  document.body.classList.add("no-scroll");
  const closeBtn = $(id).querySelector(".modal-close");
  if(closeBtn) closeBtn.focus();
}
function closeOverlay(el){
  el.classList.remove("open");
  if(!document.querySelector(".overlay.open")) document.body.classList.remove("no-scroll");
}
$("sizeGuideBtn").addEventListener("click", ()=>openOverlay("sizeOverlay"));
$("sizeGuideFooter").addEventListener("click", ()=>openOverlay("sizeOverlay"));
$("wishlistBtn").addEventListener("click", ()=>{ renderWishModal(); openOverlay("wishOverlay"); });
document.querySelectorAll(".overlay").forEach(ov=>{
  ov.addEventListener("click", e=>{ if(e.target===ov) closeOverlay(ov); });
});
document.querySelectorAll("[data-close]").forEach(btn=>{
  btn.addEventListener("click", ()=>closeOverlay($(btn.dataset.close)));
});

/* ---------- simple page router (Home / Clothing / About / Contact) ---------- */
const PAGE_NAMES = ["home","shop","about","contact"];
function showPage(name){
  if(!PAGE_NAMES.includes(name)) name = "home";
  document.querySelectorAll(".page").forEach(p=>p.classList.toggle("active", p.id==="page-"+name));
  document.querySelectorAll(".nav-links a").forEach(a=>a.classList.toggle("active", a.dataset.page===name));
  window.scrollTo({top:0,behavior:"auto"});
}
window.addEventListener("hashchange", ()=>showPage(location.hash.replace("#","")));
document.querySelectorAll("[data-page]").forEach(a=>{
  a.addEventListener("click", ()=>showPage(a.dataset.page));
});

/* footer category shortcuts jump straight to that section of the Clothing page */
document.querySelectorAll("[data-col-link]").forEach(a=>{
  a.addEventListener("click", ()=>{
    state.collection = a.dataset.colLink;
    renderTabs(); renderGrid();
  });
});

/* contact form → opens Gmail with the message ready */
$("cfSend").addEventListener("click", ()=>{
  const name = $("cfName").value.trim();
  const msg  = $("cfMsg").value.trim();
  if(!msg){ toast("Write a message first"); return; }
  openGmail(
    "Message from the NWL website" + (name ? " — " + name : ""),
    msg + (name ? "\n\n— " + name : "")
  );
  toast("Opening Gmail…");
});

/* ---------- boot ---------- */
renderTabs();
renderFilters();
renderGrid();
renderHomeRecs();
showPage(location.hash.replace("#","") || "home");
